import type { PublicCard } from '../../../types';

export const gcseExamQuestionsCardsPart2: PublicCard[] = [
  // GEOMETRY Part 2 (151-175)
  { id: 'dc-gcse-examq-0151', deck_id: 'deck-gcse-exam-questions', front: 'A right-angled triangle has hypotenuse 13 cm and one leg 5 cm. Find the other leg.', back: 'b² = 13² − 5² = 169 − 25 = 144\nb = 12 cm\n\nGCSE Tip: 5-12-13 is a Pythagorean triple. Rearrange Pythagoras: shorter leg = √(hyp² − other leg²).', sort_order: 151 },
  { id: 'dc-gcse-examq-0152', deck_id: 'deck-gcse-exam-questions', front: 'In triangle ABC, AB = 7 cm, BC = 9 cm and angle B = 60°. Find AC using the cosine rule.', back: 'AC² = AB² + BC² − 2(AB)(BC)cos B\n= 49 + 81 − 2(7)(9)cos60°\n= 130 − 126(0.5)\n= 130 − 63 = 67\nAC = √67 ≈ 8.19 cm\n\nGCSE Tip: Cosine rule for finding a side: a² = b² + c² − 2bc cos A.', sort_order: 152 },
  { id: 'dc-gcse-examq-0153', deck_id: 'deck-gcse-exam-questions', front: 'In a triangle, sides are a = 5, b = 7, c = 8. Find angle A using the cosine rule.', back: 'cos A = (b² + c² − a²)/(2bc) = (49 + 64 − 25)/(2×7×8) = 88/112 = 11/14\nA = cos⁻¹(11/14) ≈ 38.2°\n\nGCSE Tip: Cosine rule to find angle: cos A = (b²+c²−a²)/(2bc). Angle A is opposite side a.', sort_order: 153 },
  { id: 'dc-gcse-examq-0154', deck_id: 'deck-gcse-exam-questions', front: 'In triangle ABC, AB = 6 cm, angle A = 35°, angle B = 80°. Find BC using the sine rule.', back: 'Angle C = 180 − 35 − 80 = 65°\nBC/sinA = AB/sinC\nBC/sin35° = 6/sin65°\nBC = 6 × sin35° / sin65° = 6 × 0.5736/0.9063 ≈ 3.79 cm\n\nGCSE Tip: Sine rule: a/sinA = b/sinB = c/sinC. Use when given a side and the opposite angle.', sort_order: 154 },
  { id: 'dc-gcse-examq-0155', deck_id: 'deck-gcse-exam-questions', front: 'A chord of length 8 cm is 3 cm from the centre of a circle. Find the radius.', back: 'The perpendicular from centre bisects the chord.\nHalf-chord = 4 cm, distance from centre = 3 cm\nr² = 4² + 3² = 16 + 9 = 25\nr = 5 cm\n\nGCSE Tip: Draw the radius to the chord endpoint. You get a right triangle with hypotenuse = radius.', sort_order: 155 },
  { id: 'dc-gcse-examq-0156', deck_id: 'deck-gcse-exam-questions', front: 'State the theorem about the angle in a semicircle. If AB is a diameter, what is angle ACB for any point C on the circle?', back: 'Angle in a semicircle = 90°\nAngle ACB = 90° for any point C on the circle (other than A and B).\n\nGCSE Tip: The angle subtended by a diameter at the circumference is always a right angle. This is one of the key circle theorems.', sort_order: 156 },
  { id: 'dc-gcse-examq-0157', deck_id: 'deck-gcse-exam-questions', front: 'Two tangents from external point P to a circle are each 6 cm. OP = 10 cm. Find the radius of the circle.', back: 'Tangent meets radius at 90°, so right angle at T.\nr² + 6² = 10² (but tangent length ≠ 6; tangent=6, OP=10)\nr² = 10² − 6² = 100 − 36 = 64\nr = 8 cm\n\nGCSE Tip: Tangent is perpendicular to radius. Use Pythagoras: OP² = r² + tangent length².', sort_order: 157 },
  { id: 'dc-gcse-examq-0158', deck_id: 'deck-gcse-exam-questions', front: 'State the alternate segment theorem.', back: 'The angle between a tangent and a chord at the point of tangency equals the inscribed angle subtending the same chord from the other side.\n\nExample: If TPA is tangent at P and PAB is a chord, then angle TPA (between tangent and chord) = angle PBA (in the alternate segment).\n\nGCSE Tip: "Alternate segment theorem" — tangent-chord angle = angle in alternate segment.', sort_order: 158 },
  { id: 'dc-gcse-examq-0159', deck_id: 'deck-gcse-exam-questions', front: 'The angle at the centre of a circle is 110°. What is the angle at the circumference subtending the same arc?', back: 'Angle at circumference = 110° ÷ 2 = 55°\n\nGCSE Tip: Angle at centre = 2 × angle at circumference (for the same arc). This is the central angle theorem.', sort_order: 159 },
  { id: 'dc-gcse-examq-0160', deck_id: 'deck-gcse-exam-questions', front: 'ABCD is a cyclic quadrilateral with angle A = 85°. Find angle C.', back: 'Opposite angles of a cyclic quadrilateral sum to 180°.\nAngle C = 180° − 85° = 95°\n\nGCSE Tip: Cyclic quadrilateral: opposite angles add up to 180° (they are supplementary).', sort_order: 160 },
  { id: 'dc-gcse-examq-0161', deck_id: 'deck-gcse-exam-questions', front: 'Find the perpendicular height of an equilateral triangle with side length 10 cm.', back: 'Split into two right triangles: base = 5, hypotenuse = 10\nh² = 10² − 5² = 100 − 25 = 75\nh = √75 = 5√3 ≈ 8.66 cm\n\nGCSE Tip: Perpendicular bisects the base. Height = (√3/2) × side.', sort_order: 161 },
  { id: 'dc-gcse-examq-0162', deck_id: 'deck-gcse-exam-questions', front: 'A rectangle is 6 cm × 8 cm. Find the length of its diagonal.', back: 'd² = 6² + 8² = 36 + 64 = 100\nd = 10 cm\n\nGCSE Tip: 6-8-10 is a Pythagorean triple (3-4-5 scaled by 2). Pythagoras applied to the diagonal.', sort_order: 162 },
  { id: 'dc-gcse-examq-0163', deck_id: 'deck-gcse-exam-questions', front: 'A 5 m ladder leans against a wall. Its foot is 3 m from the wall. How high up the wall does it reach?', back: 'h² = 5² − 3² = 25 − 9 = 16\nh = 4 m\n\nGCSE Tip: 3-4-5 Pythagorean triple. The wall, floor and ladder form a right triangle.', sort_order: 163 },
  { id: 'dc-gcse-examq-0164', deck_id: 'deck-gcse-exam-questions', front: 'A cuboid has dimensions 4 cm × 3 cm × 2 cm. Find the length of the space diagonal.', back: 'Space diagonal² = 4² + 3² + 2² = 16 + 9 + 4 = 29\nSpace diagonal = √29 ≈ 5.39 cm\n\nGCSE Tip: 3D Pythagoras: d = √(l² + w² + h²). Apply Pythagoras twice or use this formula directly.', sort_order: 164 },
  { id: 'dc-gcse-examq-0165', deck_id: 'deck-gcse-exam-questions', front: 'A pyramid has a square base of side 6 cm and height 4 cm. Find its volume.', back: 'V = (1/3) × base area × height\n= (1/3) × 36 × 4 = 48 cm³\n\nGCSE Tip: Volume of any pyramid = (1/3) × base area × perpendicular height.', sort_order: 165 },
  { id: 'dc-gcse-examq-0166', deck_id: 'deck-gcse-exam-questions', front: 'A cone has slant height 13 cm and base radius 5 cm. Find its curved surface area.', back: 'Curved SA = πrl = π × 5 × 13 = 65π cm² ≈ 204.2 cm²\n\nGCSE Tip: Curved SA of cone = πrl where r = radius, l = slant height (not perpendicular height).', sort_order: 166 },
  { id: 'dc-gcse-examq-0167', deck_id: 'deck-gcse-exam-questions', front: 'A sector has radius 12 cm and area 60π cm². Find its arc length.', back: 'Area = (θ/360)πr² → 60π = (θ/360)×144π → θ/360 = 60/144 = 5/12 → θ = 150°\nArc length = (150/360) × 2π × 12 = (5/12) × 24π = 10π cm\n\nGCSE Tip: Find the angle first from the area, then use it to find the arc length.', sort_order: 167 },
  { id: 'dc-gcse-examq-0168', deck_id: 'deck-gcse-exam-questions', front: 'A solid is made of a cylinder (r = 3 cm, h = 5 cm) with a hemisphere (r = 3 cm) on top. Find the total volume.', back: 'Cylinder: π(3²)(5) = 45π cm³\nHemisphere: (1/2)(4/3)π(3³) = (1/2)(36π) = 18π cm³\nTotal = 63π cm³ ≈ 197.9 cm³\n\nGCSE Tip: Add volumes of each component. Hemisphere = half of sphere = (2/3)πr³.', sort_order: 168 },
  { id: 'dc-gcse-examq-0169', deck_id: 'deck-gcse-exam-questions', front: 'Two similar shapes have corresponding sides in ratio 3:5. What is the ratio of their areas?', back: 'Area ratio = 3² : 5² = 9 : 25\n\nGCSE Tip: For similar shapes: lengths ratio = k:1 → area ratio = k²:1 → volume ratio = k³:1.', sort_order: 169 },
  { id: 'dc-gcse-examq-0170', deck_id: 'deck-gcse-exam-questions', front: 'Two similar solids have volume ratio 8:27. Find their length ratio.', back: 'Length ratio = ³√8 : ³√27 = 2 : 3\n\nGCSE Tip: Volume ratio = k³, so length ratio = cube root of volume ratio.', sort_order: 170 },
  { id: 'dc-gcse-examq-0171', deck_id: 'deck-gcse-exam-questions', front: 'A ship sails 8 km north then 6 km east. How far is it from the start? What is its bearing from the start?', back: 'Distance = √(8² + 6²) = √100 = 10 km\nBearing: tan θ = 6/8 = 0.75 → θ = 36.9°\nBearing = 090° − but measured from North clockwise: bearing = 36.9° ≈ 037°\n\nGCSE Tip: Use Pythagoras for distance. Bearing measured clockwise from North. tan θ = opposite/adjacent.', sort_order: 171 },
  { id: 'dc-gcse-examq-0172', deck_id: 'deck-gcse-exam-questions', front: 'A bearing from A to B is 130°. What is the bearing from B back to A?', back: 'Back bearing = 130° + 180° = 310°\n\nGCSE Tip: Add or subtract 180° to find the reverse bearing. If the result > 360°, subtract 360°. If < 0°, add 360°.', sort_order: 172 },
  { id: 'dc-gcse-examq-0173', deck_id: 'deck-gcse-exam-questions', front: 'A pole is 5 m tall. It casts a shadow of 3 m. Find the angle of elevation of the sun.', back: 'tan θ = opposite/adjacent = 5/3\nθ = tan⁻¹(5/3) ≈ 59.0°\n\nGCSE Tip: Angle of elevation: look UP from the horizontal. tan = height/shadow length.', sort_order: 173 },
  { id: 'dc-gcse-examq-0174', deck_id: 'deck-gcse-exam-questions', front: 'Calculate the exact area of an equilateral triangle with side length 6 cm.', back: 'Height = (√3/2) × 6 = 3√3 cm\nArea = (1/2) × 6 × 3√3 = 9√3 cm²\n\nGCSE Tip: Area of equilateral triangle = (√3/4)a² where a is the side length. Here: (√3/4)×36 = 9√3.', sort_order: 174 },
  { id: 'dc-gcse-examq-0175', deck_id: 'deck-gcse-exam-questions', front: 'A sector has radius 9 cm and arc length 6π cm. Find the angle of the sector in degrees.', back: 'Arc length = (θ/360) × 2πr\n6π = (θ/360) × 18π\n6/18 = θ/360\nθ = (1/3) × 360 = 120°\n\nGCSE Tip: Arc length = (θ/360) × 2πr. Rearrange to find θ.', sort_order: 175 },

  // TRIGONOMETRY (176-205)
  { id: 'dc-gcse-examq-0176', deck_id: 'deck-gcse-exam-questions', front: 'In a right triangle, the hypotenuse is 10 cm and one angle is 30°. Find the opposite side.', back: 'sin 30° = opposite/hypotenuse\nopposite = 10 × sin30° = 10 × 0.5 = 5 cm\n\nGCSE Tip: SOH: sin = Opp/Hyp. Rearrange: Opp = Hyp × sin(angle).', sort_order: 176 },
  { id: 'dc-gcse-examq-0177', deck_id: 'deck-gcse-exam-questions', front: 'Find angle θ if sin θ = 0.6. Give answer to 1 d.p.', back: 'θ = sin⁻¹(0.6) ≈ 36.9°\n\nGCSE Tip: Use the inverse trig function (sin⁻¹) to find the angle from its ratio.', sort_order: 177 },
  { id: 'dc-gcse-examq-0178', deck_id: 'deck-gcse-exam-questions', front: 'A ladder 8 m long leans against a wall at 65° to the horizontal. How high up the wall does it reach?', back: 'Height = 8 × sin65° = 8 × 0.9063 ≈ 7.25 m\n\nGCSE Tip: The angle is with the horizontal (floor), so height = hyp × sin(angle). Draw a diagram.', sort_order: 178 },
  { id: 'dc-gcse-examq-0179', deck_id: 'deck-gcse-exam-questions', front: 'From the top of a cliff 80 m high, the angle of depression to a boat is 25°. Find the horizontal distance from the cliff to the boat.', back: 'Angle of depression = angle below horizontal = 25°\nAlternate angles: angle in right triangle = 25°\ntan25° = 80/d → d = 80/tan25° = 80/0.4663 ≈ 171.6 m\n\nGCSE Tip: Angle of depression from top = angle of elevation from boat. tan = opposite/adjacent.', sort_order: 179 },
  { id: 'dc-gcse-examq-0180', deck_id: 'deck-gcse-exam-questions', front: 'State the exact values of sin 45°, cos 45°, and tan 45°.', back: 'sin 45° = √2/2 = 1/√2\ncos 45° = √2/2 = 1/√2\ntan 45° = 1\n\nGCSE Tip: Use the 45-45-90 triangle with legs 1, 1 and hypotenuse √2. Memorise these exact values.', sort_order: 180 },
  { id: 'dc-gcse-examq-0181', deck_id: 'deck-gcse-exam-questions', front: 'State the exact values of sin 30°, cos 30°, and tan 30°.', back: 'sin 30° = 1/2\ncos 30° = √3/2\ntan 30° = 1/√3 = √3/3\n\nGCSE Tip: Use the 30-60-90 triangle (half equilateral, sides 1, √3, 2).', sort_order: 181 },
  { id: 'dc-gcse-examq-0182', deck_id: 'deck-gcse-exam-questions', front: 'State the exact values of sin 60°, cos 60°, and tan 60°.', back: 'sin 60° = √3/2\ncos 60° = 1/2\ntan 60° = √3\n\nGCSE Tip: sin 60° = cos 30° and cos 60° = sin 30° — complementary angles swap sin and cos.', sort_order: 182 },
  { id: 'dc-gcse-examq-0183', deck_id: 'deck-gcse-exam-questions', front: 'In triangle ABC, a = 7, b = 9, C = 65°. Find side c using the cosine rule.', back: 'c² = a² + b² − 2ab cos C\n= 49 + 81 − 2(7)(9)cos65°\n= 130 − 126(0.4226)\n= 130 − 53.25 = 76.75\nc = √76.75 ≈ 8.76 cm\n\nGCSE Tip: The cosine rule connects two sides and the included angle to find the third side.', sort_order: 183 },
  { id: 'dc-gcse-examq-0184', deck_id: 'deck-gcse-exam-questions', front: 'In a triangle, a = 10, b = 14, c = 18. Find angle B using the cosine rule.', back: 'cos B = (a² + c² − b²)/(2ac) = (100 + 324 − 196)/(2×10×18) = 228/360 = 0.6333\nB = cos⁻¹(0.6333) ≈ 50.7°\n\nGCSE Tip: To find angle B: cos B = (a²+c²−b²)/(2ac). Note: b and B must be the same vertex/opposite side.', sort_order: 184 },
  { id: 'dc-gcse-examq-0185', deck_id: 'deck-gcse-exam-questions', front: 'In triangle ABC, a = 8 cm, angle A = 75°, angle B = 40°. Find side b using the sine rule.', back: 'b/sinB = a/sinA\nb = a × sinB/sinA = 8 × sin40°/sin75°\n= 8 × 0.6428/0.9659 ≈ 5.32 cm\n\nGCSE Tip: Sine rule: a/sinA = b/sinB. Use when you know a side and the opposite angle.', sort_order: 185 },
  { id: 'dc-gcse-examq-0186', deck_id: 'deck-gcse-exam-questions', front: 'Triangle ABC has AB = 6 cm, AC = 9 cm and angle A = 50°. Find its area.', back: 'Area = (1/2)ab sinC = (1/2)(6)(9)sin50°\n= 27 × 0.7660 ≈ 20.68 cm²\n\nGCSE Tip: Area = (1/2)ab sinC uses two sides and the INCLUDED angle. Learn this formula.', sort_order: 186 },
  { id: 'dc-gcse-examq-0187', deck_id: 'deck-gcse-exam-questions', front: 'Find all solutions of sin x = 0.5 for 0° ≤ x ≤ 360°.', back: 'First solution: x = sin⁻¹(0.5) = 30°\nSecond solution: x = 180° − 30° = 150°\nSolutions: x = 30° and x = 150°\n\nGCSE Tip: sin is positive in 1st and 2nd quadrants. Second solution = 180° − first. Check using sin graph.', sort_order: 187 },
  { id: 'dc-gcse-examq-0188', deck_id: 'deck-gcse-exam-questions', front: 'Find all solutions of cos x = −1/2 for 0° ≤ x ≤ 360°.', back: 'Reference angle: cos⁻¹(1/2) = 60°\ncos is negative in 2nd and 3rd quadrants.\nx = 180° − 60° = 120° or x = 180° + 60° = 240°\n\nGCSE Tip: cos negative → 2nd quadrant (180°−θ) and 3rd quadrant (180°+θ).', sort_order: 188 },
  { id: 'dc-gcse-examq-0189', deck_id: 'deck-gcse-exam-questions', front: 'State the Pythagorean identity and use it to find sin θ if cos θ = 3/5 (θ acute).', back: 'Identity: sin²θ + cos²θ = 1\nsin²θ = 1 − (3/5)² = 1 − 9/25 = 16/25\nsin θ = 4/5 (positive, θ acute)\n\nGCSE Tip: sin²θ + cos²θ = 1 always. Rearrange to find the unknown trig ratio.', sort_order: 189 },
  { id: 'dc-gcse-examq-0190', deck_id: 'deck-gcse-exam-questions', front: 'A triangle has area 35 cm². Two sides are 7 cm and 10 cm. Find the included angle.', back: 'Area = (1/2)ab sinC\n35 = (1/2)(7)(10)sinC\n35 = 35 sinC\nsin C = 1 → C = 90°\n\nGCSE Tip: Rearrange the formula: sin C = (2 × Area)/(ab). Then use sin⁻¹ to find C.', sort_order: 190 },
  { id: 'dc-gcse-examq-0191', deck_id: 'deck-gcse-exam-questions', front: 'Find the exact value of tan 60°.', back: 'tan 60° = √3 ≈ 1.732\n\nDerived from 30-60-90 triangle: opposite = √3, adjacent = 1.\ntan 60° = √3/1 = √3\n\nGCSE Tip: Memorise exact trig values for 30°, 45°, 60°. Essential for non-calculator papers.', sort_order: 191 },
  { id: 'dc-gcse-examq-0192', deck_id: 'deck-gcse-exam-questions', front: 'Find the angle of elevation to the top of a 50 m building from a point 30 m away (at ground level).', back: 'tan θ = 50/30 = 5/3\nθ = tan⁻¹(5/3) ≈ 59.0°\n\nGCSE Tip: The observer is at the base. It\'s a right triangle with opposite = height, adjacent = distance.', sort_order: 192 },
  { id: 'dc-gcse-examq-0193', deck_id: 'deck-gcse-exam-questions', front: 'Find the exact value of sin 30° + cos 60°.', back: 'sin 30° = 1/2\ncos 60° = 1/2\nsin 30° + cos 60° = 1/2 + 1/2 = 1\n\nGCSE Tip: sin 30° = cos 60° because they are complementary (30°+60°=90°). sin θ = cos(90°−θ).', sort_order: 193 },
  { id: 'dc-gcse-examq-0194', deck_id: 'deck-gcse-exam-questions', front: 'In a right triangle, opposite = 5 and adjacent = 12. Find all three basic trig ratios.', back: 'Hypotenuse = √(5²+12²) = √169 = 13\nsin θ = 5/13\ncos θ = 12/13\ntan θ = 5/12\n\nGCSE Tip: SOH-CAH-TOA. Always find the hypotenuse using Pythagoras before writing all three ratios.', sort_order: 194 },
  { id: 'dc-gcse-examq-0195', deck_id: 'deck-gcse-exam-questions', front: 'Describe the graph of y = sin x for 0° ≤ x ≤ 360°. State maximum value, minimum value and period.', back: 'Maximum value: 1 (at x = 90°)\nMinimum value: −1 (at x = 270°)\nPeriod: 360°\nCrosses x-axis at: 0°, 180°, 360°\n\nGCSE Tip: Know the key features of sin, cos and tan graphs — amplitude, period, and key coordinates.', sort_order: 195 },
  { id: 'dc-gcse-examq-0196', deck_id: 'deck-gcse-exam-questions', front: 'State the period and amplitude of y = 3 sin(2x).', back: 'Amplitude = 3 (the coefficient in front of sin)\nPeriod = 360°/2 = 180°\n\nGCSE Tip: y = a sin(bx): amplitude = |a|, period = 360°/b. The graph is taller (×3) and twice as compressed.', sort_order: 196 },
  { id: 'dc-gcse-examq-0197', deck_id: 'deck-gcse-exam-questions', front: 'Describe the transformation from y = sin x to y = sin(x − 90°).', back: 'Translation by vector (90°, 0) — the graph shifts 90° to the RIGHT.\n\nGCSE Tip: y = sin(x − a) shifts RIGHT by a. Note: this graph is the same as y = −cos x.', sort_order: 197 },
  { id: 'dc-gcse-examq-0198', deck_id: 'deck-gcse-exam-questions', front: 'Find all solutions of tan θ = 1 for 0° ≤ θ ≤ 360°.', back: 'First solution: θ = tan⁻¹(1) = 45°\ntan repeats every 180°\nSecond solution: θ = 45° + 180° = 225°\nSolutions: 45° and 225°\n\nGCSE Tip: tan is positive in 1st and 3rd quadrants. Period of tan = 180°.', sort_order: 198 },
  { id: 'dc-gcse-examq-0199', deck_id: 'deck-gcse-exam-questions', front: 'A ship sails on bearing 070° for 15 km then bearing 160° for 20 km. Find the straight-line distance from the start.', back: 'Angle between directions = 160° − 70° = 90°\n(Perpendicular paths — confirm: N70°E then S70°E = 90° between them)\nd = √(15² + 20²) = √(225 + 400) = √625 = 25 km\n\nGCSE Tip: Find the angle between the two legs. Use cosine rule if not 90°, Pythagoras if 90°.', sort_order: 199 },
  { id: 'dc-gcse-examq-0200', deck_id: 'deck-gcse-exam-questions', front: 'Find the largest angle in a triangle with sides 5 cm, 6 cm and 7 cm.', back: 'Largest angle is opposite the longest side (7 cm). Call it C, so c=7, a=5, b=6.\ncos C = (25+36−49)/(2×5×6) = 12/60 = 0.2\nC = cos⁻¹(0.2) ≈ 78.5°\n\nGCSE Tip: Largest angle is always opposite the longest side. Use cosine rule.', sort_order: 200 },
  { id: 'dc-gcse-examq-0201', deck_id: 'deck-gcse-exam-questions', front: 'An isosceles triangle has equal sides of 8 cm and a base of 6 cm. Find the base angles.', back: 'Split into two right triangles: base half = 3, hypotenuse = 8.\ncos θ = 3/8 → θ = cos⁻¹(3/8) ≈ 67.98° ≈ 68.0°\n\nGCSE Tip: The perpendicular from apex bisects the base. Right triangle: adj = 3, hyp = 8.', sort_order: 201 },
  { id: 'dc-gcse-examq-0202', deck_id: 'deck-gcse-exam-questions', front: 'Solve sin²x + sin x = 0 for 0° ≤ x ≤ 360°.', back: 'sin x(sin x + 1) = 0\nsin x = 0: x = 0°, 180°, 360°\nsin x = −1: x = 270°\nSolutions: 0°, 180°, 270°, 360°\n\nGCSE Tip: Factorise the trigonometric equation. Solve each factor separately.', sort_order: 202 },
  { id: 'dc-gcse-examq-0203', deck_id: 'deck-gcse-exam-questions', front: 'Prove that sin θ / cos θ = tan θ.', back: 'In a right triangle with angle θ:\nsin θ = opposite/hypotenuse\ncos θ = adjacent/hypotenuse\nsin θ / cos θ = (opp/hyp) ÷ (adj/hyp) = opp/adj = tan θ ✓\n\nGCSE Tip: Dividing the definitions gives the identity directly. This is a key trig identity.', sort_order: 203 },
  { id: 'dc-gcse-examq-0204', deck_id: 'deck-gcse-exam-questions', front: 'A kite has diagonals of length 10 cm and 6 cm. Find its area.', back: 'Area of kite = (1/2) × d₁ × d₂ = (1/2) × 10 × 6 = 30 cm²\n\nGCSE Tip: Area of kite (and rhombus) = half the product of the diagonals.', sort_order: 204 },
  { id: 'dc-gcse-examq-0205', deck_id: 'deck-gcse-exam-questions', front: 'Find all solutions of cos 2x = 0.5 for 0° ≤ x ≤ 360°.', back: 'Let u = 2x, range: 0° ≤ u ≤ 720°\ncos u = 0.5 → u = 60°, 300°, 420°, 660°\n2x = 60°, 300°, 420°, 660°\nx = 30°, 150°, 210°, 330°\n\nGCSE Tip: Double the range when substituting. cos 0.5 = 60°; other solutions by symmetry.', sort_order: 205 },

  // STATISTICS (206-245)
  { id: 'dc-gcse-examq-0206', deck_id: 'deck-gcse-exam-questions', front: 'Find the mean, median, mode and range of: 4, 7, 2, 7, 9, 3, 7, 5.', back: 'Order: 2, 3, 4, 5, 7, 7, 7, 9\nMean = (2+3+4+5+7+7+7+9)/8 = 44/8 = 5.5\nMedian = (5+7)/2 = 6 (middle two values)\nMode = 7 (most frequent)\nRange = 9 − 2 = 7\n\nGCSE Tip: Always sort data first. Median of 8 values = average of 4th and 5th.', sort_order: 206 },
  { id: 'dc-gcse-examq-0207', deck_id: 'deck-gcse-exam-questions', front: 'The mean of 5 numbers is 12. Four of them are 10, 14, 9 and 15. Find the fifth number.', back: 'Total = 5 × 12 = 60\nSum of four = 10+14+9+15 = 48\nFifth number = 60 − 48 = 12\n\nGCSE Tip: Total = mean × number of values. Subtract the known sum to find the unknown.', sort_order: 207 },
  { id: 'dc-gcse-examq-0208', deck_id: 'deck-gcse-exam-questions', front: 'Find the estimated mean from grouped data: 0–10 (f = 4), 10–20 (f = 7), 20–30 (f = 3).', back: 'Midpoints: 5, 15, 25\nΣfx = 4×5 + 7×15 + 3×25 = 20 + 105 + 75 = 200\nΣf = 4 + 7 + 3 = 14\nMean = 200/14 ≈ 14.3\n\nGCSE Tip: Use the midpoint of each class. Estimated mean = Σfx ÷ Σf.', sort_order: 208 },
  { id: 'dc-gcse-examq-0209', deck_id: 'deck-gcse-exam-questions', front: 'A class\'s test scores are: 42, 45, 51, 53, 57, 58, 63, 65, 67. Find the median and IQR.', back: 'n = 9, median = 5th value = 57\nQ1 = median of lower half (42,45,51,53) = (45+51)/2 = 48\nQ3 = median of upper half (58,63,65,67) = (63+65)/2 = 64\nIQR = Q3 − Q1 = 64 − 48 = 16\n\nGCSE Tip: For 9 values, median is 5th. Q1 is median of bottom 4, Q3 is median of top 4.', sort_order: 209 },
  { id: 'dc-gcse-examq-0210', deck_id: 'deck-gcse-exam-questions', front: 'From a cumulative frequency graph with 60 data points, how do you find the median, Q1 and Q3?', back: 'Median: read off at cumulative frequency = 30 (60 ÷ 2)\nQ1: read off at cf = 15 (60 ÷ 4)\nQ3: read off at cf = 45 (3 × 60 ÷ 4)\n\nGCSE Tip: Median at n/2, Q1 at n/4, Q3 at 3n/4. Draw a horizontal line across to the curve, then read off the x-axis.', sort_order: 210 },
  { id: 'dc-gcse-examq-0211', deck_id: 'deck-gcse-exam-questions', front: 'A frequency table shows: 0 (f=3), 1 (f=7), 2 (f=5). Find the mean and median.', back: 'Mean: Σfx = 0×3+1×7+2×5 = 0+7+10=17; Σf=15; Mean=17/15 ≈ 1.13\nMedian: 15 values, median = 8th value\nCumulative: 3, 10, 15. 8th value is in frequency 1 group.\nMedian = 1\n\nGCSE Tip: Build a cumulative frequency column to find the median position.', sort_order: 211 },
  { id: 'dc-gcse-examq-0212', deck_id: 'deck-gcse-exam-questions', front: 'Frequency density = frequency ÷ class width. A class 10–15 has frequency 30. What is the frequency density?', back: 'Class width = 15 − 10 = 5\nFrequency density = 30 ÷ 5 = 6\n\nGCSE Tip: For histograms with unequal class widths, use frequency density (not frequency) on the y-axis.', sort_order: 212 },
  { id: 'dc-gcse-examq-0213', deck_id: 'deck-gcse-exam-questions', front: 'A histogram bar for class 0–4 has height (frequency density) 5. Class width = 4. What is the frequency?', back: 'Frequency = frequency density × class width = 5 × 4 = 20\n\nGCSE Tip: Frequency = frequency density × class width. This is the AREA of the bar, not the height.', sort_order: 213 },
  { id: 'dc-gcse-examq-0214', deck_id: 'deck-gcse-exam-questions', front: 'A box plot has: min = 5, Q1 = 12, median = 18, Q3 = 24, max = 30. Find the IQR and comment on skew.', back: 'IQR = Q3 − Q1 = 24 − 12 = 12\nMedian − Q1 = 6; Q3 − Median = 6 → symmetric distribution (no skew)\n\nGCSE Tip: IQR = Q3−Q1. Positive skew: median closer to Q1. Negative skew: median closer to Q3.', sort_order: 214 },
  { id: 'dc-gcse-examq-0215', deck_id: 'deck-gcse-exam-questions', front: 'A scatter graph shows a negative correlation. Describe what this means in context.', back: 'As one variable increases, the other tends to decrease.\nFor example: as temperature increases, the number of hot drinks sold decreases.\n\nGCSE Tip: Negative correlation → negative gradient on line of best fit. Always describe in context.', sort_order: 215 },
  { id: 'dc-gcse-examq-0216', deck_id: 'deck-gcse-exam-questions', front: 'A correlation coefficient is −0.9. What does this indicate?', back: 'Strong negative correlation.\nThe two variables are strongly associated: as one increases, the other decreases.\n−0.9 is close to −1 (perfect negative correlation).\n\nGCSE Tip: PMCC ranges from −1 to +1. Close to ±1 = strong; close to 0 = weak.', sort_order: 216 },
  { id: 'dc-gcse-examq-0217', deck_id: 'deck-gcse-exam-questions', front: 'Give an example to distinguish correlation from causation.', back: 'Correlation: ice cream sales and drowning rates both increase in summer.\nBut ice cream does NOT cause drowning — both are caused by hot weather (confounding variable).\n\nGCSE Tip: Correlation means two things are associated. Causation means one CAUSES the other. Correlation ≠ causation.', sort_order: 217 },
  { id: 'dc-gcse-examq-0218', deck_id: 'deck-gcse-exam-questions', front: 'A school has 200 boys and 300 girls. A stratified sample of 50 is needed. How many girls should be in the sample?', back: 'Total students = 500\nGirls proportion = 300/500 = 3/5\nGirls in sample = (3/5) × 50 = 30\n\nGCSE Tip: Stratified sample: each group is sampled proportionally. Girls = (300/500) × 50 = 30.', sort_order: 218 },
  { id: 'dc-gcse-examq-0219', deck_id: 'deck-gcse-exam-questions', front: 'Calculate the estimated mean from: class 1–3 (f = 2), 3–5 (f = 8), 5–7 (f = 5).', back: 'Midpoints: 2, 4, 6\nΣfx = 2×2 + 8×4 + 5×6 = 4 + 32 + 30 = 66\nΣf = 15\nEstimated mean = 66/15 = 4.4\n\nGCSE Tip: Use class midpoints, multiply by frequency, sum up, divide by total frequency.', sort_order: 219 },
  { id: 'dc-gcse-examq-0220', deck_id: 'deck-gcse-exam-questions', front: 'Identify the modal class from: 0–5 (f = 3), 5–10 (f = 9), 10–15 (f = 5).', back: 'Modal class = 5–10 (highest frequency = 9)\n\nGCSE Tip: For grouped data, the mode is reported as the modal CLASS (the group with the highest frequency).', sort_order: 220 },
  { id: 'dc-gcse-examq-0221', deck_id: 'deck-gcse-exam-questions', front: 'Data: 0–20 (f = 6), 20–40 (f = 14), 40–60 (f = 10). Total = 30 values. Find the median class.', back: 'Median position = 30/2 = 15th value\nCumulative frequencies: 6, 20, 30\nThe 15th value falls in the 20–40 class.\nMedian class = 20–40\n\nGCSE Tip: Median is at n/2 = 15th value. Find which class contains the 15th value using cumulative frequency.', sort_order: 221 },
  { id: 'dc-gcse-examq-0222', deck_id: 'deck-gcse-exam-questions', front: 'Using interpolation, estimate the median from: 0–20 (f = 6), 20–40 (f = 14). Median is the 15th value.', back: '9 more values needed into the 20–40 class (15 − 6 = 9)\nEstimated median = 20 + (9/14) × 20 = 20 + 12.86 ≈ 32.9\n\nGCSE Tip: Interpolation: median = lower boundary + (values needed/class frequency) × class width.', sort_order: 222 },
  { id: 'dc-gcse-examq-0223', deck_id: 'deck-gcse-exam-questions', front: 'In a pie chart, 360 students were surveyed and 90 like maths. What angle represents maths?', back: 'Angle = (90/360) × 360° = 90°\n\nGCSE Tip: Angle = (frequency/total) × 360°. Here 90 out of 360 = 1/4 → 90°.', sort_order: 223 },
  { id: 'dc-gcse-examq-0224', deck_id: 'deck-gcse-exam-questions', front: 'Describe two limitations of using the mean as a measure of average.', back: '1. Affected by outliers — one extreme value can distort the mean significantly.\n2. May not be a data value in the set (e.g., mean of 1,2,3 = 2, but mean of 1,2,4 = 2.33).\n\nGCSE Tip: Use median when data has outliers. Use mode for categorical data.', sort_order: 224 },
  { id: 'dc-gcse-examq-0225', deck_id: 'deck-gcse-exam-questions', front: 'Age data: 15, 17, 18, 21, 22, 25, 28, 35, 62. Use the IQR to determine if 62 is an outlier.', back: 'Q1 = 18 (3rd value), Q3 = 28 (7th value) [from ordered data of 9]\nIQR = 28 − 18 = 10\nOutlier if > Q3 + 1.5×IQR = 28 + 15 = 43\n62 > 43 → 62 is an outlier ✓\n\nGCSE Tip: Outlier criterion: above Q3 + 1.5×IQR or below Q1 − 1.5×IQR.', sort_order: 225 },
  { id: 'dc-gcse-examq-0226', deck_id: 'deck-gcse-exam-questions', front: 'State the difference between discrete and continuous data. Give one example of each.', back: 'Discrete: can only take specific separate values (often whole numbers). Example: number of children.\nContinuous: can take any value in a range. Example: height, weight, temperature.\n\nGCSE Tip: If you can count it → discrete. If you measure it → continuous.', sort_order: 226 },
  { id: 'dc-gcse-examq-0227', deck_id: 'deck-gcse-exam-questions', front: 'Calculate the mean of: 50, 60, 70 with frequencies 3, 5, 2.', back: 'Σfx = 50×3 + 60×5 + 70×2 = 150 + 300 + 140 = 590\nΣf = 3 + 5 + 2 = 10\nMean = 590/10 = 59\n\nGCSE Tip: Mean from frequency table = Σ(value × frequency) ÷ total frequency.', sort_order: 227 },
  { id: 'dc-gcse-examq-0228', deck_id: 'deck-gcse-exam-questions', front: 'The range is 26 and the minimum value is 14. What is the maximum value?', back: 'Maximum = minimum + range = 14 + 26 = 40\n\nGCSE Tip: Range = max − min. Rearrange: max = min + range.', sort_order: 228 },
  { id: 'dc-gcse-examq-0229', deck_id: 'deck-gcse-exam-questions', front: 'A data set has a mean of 30. Each value is increased by 5. What is the new mean?', back: 'New mean = 30 + 5 = 35\n\nGCSE Tip: Adding a constant to each value increases the mean by that constant. The standard deviation stays the same.', sort_order: 229 },
  { id: 'dc-gcse-examq-0230', deck_id: 'deck-gcse-exam-questions', front: 'Calculate the 3-point moving averages for the data: 5, 8, 6, 9, 7.', back: 'MA1 = (5+8+6)/3 = 19/3 ≈ 6.33\nMA2 = (8+6+9)/3 = 23/3 ≈ 7.67\nMA3 = (6+9+7)/3 = 22/3 ≈ 7.33\n\nGCSE Tip: Each moving average uses three consecutive values. Plot at the middle time point.', sort_order: 230 },
  { id: 'dc-gcse-examq-0231', deck_id: 'deck-gcse-exam-questions', front: 'A histogram class 20–30 has frequency density 3.5 and class 30–45 has frequency density 2. Compare their frequencies.', back: 'Class 20–30: width=10, freq = 3.5×10 = 35\nClass 30–45: width=15, freq = 2×15 = 30\nClass 20–30 has a higher frequency despite a shorter bar could mislead.\n\nGCSE Tip: In histograms, AREA = frequency, not height. Always check class width.', sort_order: 231 },
  { id: 'dc-gcse-examq-0232', deck_id: 'deck-gcse-exam-questions', front: 'Explain why a question such as "Don\'t you agree that homework is too hard?" is a biased survey question.', back: 'It is a leading question — it suggests the "correct" answer, encouraging the respondent to agree.\n\nImproved question: "How would you rate the difficulty of homework? (Too easy / About right / Too hard)"\n\nGCSE Tip: Good survey questions are neutral, unambiguous, and offer balanced response options.', sort_order: 232 },
  { id: 'dc-gcse-examq-0233', deck_id: 'deck-gcse-exam-questions', front: 'A cumulative frequency graph has 80 data points. Estimate how many data values are above the upper quartile.', back: 'Upper quartile is at 3n/4 = 60th value.\n25% of data lies above Q3.\n0.25 × 80 = 20 values\n\nGCSE Tip: By definition, 25% of data lies above Q3. For 80 values: 80 × 0.25 = 20.', sort_order: 233 },
  { id: 'dc-gcse-examq-0234', deck_id: 'deck-gcse-exam-questions', front: 'What does it mean if the PMCC (correlation coefficient) is 0?', back: 'PMCC = 0 indicates no linear correlation between the two variables.\n\nNote: there could still be a non-linear relationship (e.g., quadratic).\n\nGCSE Tip: PMCC measures LINEAR correlation only. Values close to +1 or −1 = strong linear correlation.', sort_order: 234 },
  { id: 'dc-gcse-examq-0235', deck_id: 'deck-gcse-exam-questions', front: 'How do you draw a frequency polygon from a grouped frequency table?', back: '1. Find the midpoint of each class.\n2. Plot (midpoint, frequency) for each class.\n3. Join the points with straight lines.\n4. Extend the line to zero frequency at the midpoints of the classes before and after.\n\nGCSE Tip: Plot midpoints, not boundaries. The polygon should start and end on the x-axis.', sort_order: 235 },
  { id: 'dc-gcse-examq-0236', deck_id: 'deck-gcse-exam-questions', front: 'A time series shows an upward trend. How do you use it to make a prediction?', back: '1. Plot the data and draw a line of best fit (trend line).\n2. Extend the trend line.\n3. Read off the predicted value at the future time period.\n\nNote: Extrapolation (predicting beyond the data range) is less reliable.\n\nGCSE Tip: Interpolation (within the range) is more reliable than extrapolation (beyond the range).', sort_order: 236 },
  { id: 'dc-gcse-examq-0237', deck_id: 'deck-gcse-exam-questions', front: 'Four features to compare when looking at two box plots.', back: '1. Medians — which group has a higher median (central tendency)?\n2. IQRs — which has more spread in the middle 50%?\n3. Ranges — which has more overall spread?\n4. Skewness — is the distribution symmetrical or skewed?\n\nGCSE Tip: Always compare medians AND spread. Mention both context and statistics.', sort_order: 237 },
  { id: 'dc-gcse-examq-0238', deck_id: 'deck-gcse-exam-questions', front: 'In a back-to-back stem-and-leaf diagram, leaves are on both sides. How do you find the median for one group?', back: '1. Count the total number of values for that group.\n2. Find the position of the median: (n+1)/2\n3. Count through the leaves (from the stem outward) to reach that position.\n\nGCSE Tip: Always read leaves away from the stem. For back-to-back, left group reads right-to-left.', sort_order: 238 },
  { id: 'dc-gcse-examq-0239', deck_id: 'deck-gcse-exam-questions', front: 'A class takes a test. Mean = 65, median = 58. What does this suggest about the distribution?', back: 'Mean > median suggests positive skew (skewed to the right).\nThere are likely some high scores pulling the mean up.\n\nGCSE Tip: Positive skew: mean > median > mode. Negative skew: mean < median < mode.', sort_order: 239 },
  { id: 'dc-gcse-examq-0240', deck_id: 'deck-gcse-exam-questions', front: 'What is the advantage of using the IQR over the range as a measure of spread?', back: 'The IQR is not affected by outliers or extreme values.\nThe range uses only the min and max, so one extreme outlier can give a misleading impression of spread.\n\nGCSE Tip: IQR = more robust measure of spread. Range = simpler but can be distorted by outliers.', sort_order: 240 },
  { id: 'dc-gcse-examq-0241', deck_id: 'deck-gcse-exam-questions', front: 'A histogram shows a bar for class 10–15 with height 4 and width 5. What is the frequency?', back: 'Frequency = height × width = 4 × 5 = 20\n\nGCSE Tip: In a histogram, frequency = area of bar = height (frequency density) × class width.', sort_order: 241 },
  { id: 'dc-gcse-examq-0242', deck_id: 'deck-gcse-exam-questions', front: 'Why might systematic sampling be preferred over simple random sampling?', back: 'Systematic sampling is easier to carry out — select every kth member from a list.\nIt ensures even coverage of the population.\nSimple random sampling requires a complete list and can lead to clustering by chance.\n\nGCSE Tip: Systematic = every nth item; Simple random = each item has equal chance. Both are non-biased.', sort_order: 242 },
  { id: 'dc-gcse-examq-0243', deck_id: 'deck-gcse-exam-questions', front: 'Scores 1–5 are given with frequencies 2, 4, 6, 5, 3. Find the mean score.', back: 'Σfx = 1×2+2×4+3×6+4×5+5×3 = 2+8+18+20+15 = 63\nΣf = 2+4+6+5+3 = 20\nMean = 63/20 = 3.15\n\nGCSE Tip: Mean = Σfx ÷ Σf. Build a frequency table with an fx column.', sort_order: 243 },
  { id: 'dc-gcse-examq-0244', deck_id: 'deck-gcse-exam-questions', front: 'Describe two ways in which a sample might be biased.', back: '1. Self-selection bias — only motivated people respond (e.g., online surveys).\n2. Convenience sampling — only surveying friends or nearby people who may not represent the whole population.\n\nGCSE Tip: A biased sample does not accurately represent the population. Stratified and random sampling reduce bias.', sort_order: 244 },
  { id: 'dc-gcse-examq-0245', deck_id: 'deck-gcse-exam-questions', front: 'A data set has mean 40 and standard deviation 5. A second set has mean 40 and standard deviation 12. What does this tell you?', back: 'Both sets have the same average (mean = 40).\nThe second set (SD = 12) has much greater spread/variability than the first (SD = 5).\nThe first set is more consistent.\n\nGCSE Tip: Standard deviation measures spread around the mean. Larger SD = more varied data.', sort_order: 245 },

  // PROBABILITY (246-270)
  { id: 'dc-gcse-examq-0246', deck_id: 'deck-gcse-exam-questions', front: 'A bag contains 3 red, 5 blue and 2 green balls. Find P(red).', back: 'P(red) = 3/(3+5+2) = 3/10\n\nGCSE Tip: P(event) = number of favourable outcomes / total outcomes. All outcomes must be equally likely.', sort_order: 246 },
  { id: 'dc-gcse-examq-0247', deck_id: 'deck-gcse-exam-questions', front: 'P(A) = 0.4 and P(B) = 0.3. Events A and B are mutually exclusive. Find P(A or B).', back: 'P(A ∪ B) = P(A) + P(B) = 0.4 + 0.3 = 0.7\n\nGCSE Tip: Mutually exclusive means they can\'t both happen. P(A∪B) = P(A)+P(B) only when mutually exclusive.', sort_order: 247 },
  { id: 'dc-gcse-examq-0248', deck_id: 'deck-gcse-exam-questions', front: 'P(A) = 0.6 and P(B|A) = 0.5. Find P(A and B).', back: 'P(A ∩ B) = P(A) × P(B|A) = 0.6 × 0.5 = 0.3\n\nGCSE Tip: Multiplication rule: P(A∩B) = P(A) × P(B|A). Use this for dependent events.', sort_order: 248 },
  { id: 'dc-gcse-examq-0249', deck_id: 'deck-gcse-exam-questions', front: 'A fair die is rolled twice. Find P(both show a 6).', back: 'P(6 and 6) = P(6) × P(6) = (1/6) × (1/6) = 1/36\n\nGCSE Tip: Independent events: multiply probabilities. Rolling a die twice = independent events.', sort_order: 249 },
  { id: 'dc-gcse-examq-0250', deck_id: 'deck-gcse-exam-questions', front: 'Two coins are flipped. List the sample space and find P(exactly one head).', back: 'Sample space: {HH, HT, TH, TT}\nFavourable outcomes: {HT, TH} = 2 outcomes\nP(exactly one head) = 2/4 = 1/2\n\nGCSE Tip: List ALL equally likely outcomes systematically. Count the favourable ones.', sort_order: 250 },
  { id: 'dc-gcse-examq-0251', deck_id: 'deck-gcse-exam-questions', front: 'P(rain Monday) = 0.6. P(rain Tuesday | rain Monday) = 0.7. P(rain Tuesday | no rain Monday) = 0.3. Find P(rain both days).', back: 'P(rain both) = P(rain Mon) × P(rain Tue | rain Mon)\n= 0.6 × 0.7 = 0.42\n\nGCSE Tip: Tree diagram: multiply along branches for "and". P(A and B) = P(A) × P(B|A).', sort_order: 251 },
  { id: 'dc-gcse-examq-0252', deck_id: 'deck-gcse-exam-questions', front: 'Using the rain scenario: P(rain Mon)=0.6, P(rain Tue|rain Mon)=0.7, P(rain Tue|no rain Mon)=0.3. Find P(rain exactly one day).', back: 'P(rain Mon, no Tue) = 0.6 × 0.3 = 0.18\nP(no Mon, rain Tue) = 0.4 × 0.3 = 0.12\nP(exactly one day) = 0.18 + 0.12 = 0.30\n\nGCSE Tip: "Exactly one" = two branches. Add the probabilities of both qualifying outcomes.', sort_order: 252 },
  { id: 'dc-gcse-examq-0253', deck_id: 'deck-gcse-exam-questions', front: 'P(A) = 0.5, P(B) = 0.4, P(A and B) = 0.2. Find P(A or B).', back: 'P(A ∪ B) = P(A) + P(B) − P(A ∩ B) = 0.5 + 0.4 − 0.2 = 0.7\n\nGCSE Tip: Addition rule: P(A∪B) = P(A)+P(B)−P(A∩B). Subtract the overlap to avoid counting it twice.', sort_order: 253 },
  { id: 'dc-gcse-examq-0254', deck_id: 'deck-gcse-exam-questions', front: 'A Venn diagram shows: A only = 5, B only = 7, A∩B = 3, neither = 2. Find P(A ∪ B).', back: 'Total = 5+7+3+2 = 17\nP(A∪B) = (5+7+3)/17 = 15/17\n\nGCSE Tip: P(A∪B) includes all elements in A or B (or both). Exclude "neither".', sort_order: 254 },
  { id: 'dc-gcse-examq-0255', deck_id: 'deck-gcse-exam-questions', front: 'P(not A) = 0.35. Find P(A).', back: 'P(A) = 1 − P(not A) = 1 − 0.35 = 0.65\n\nGCSE Tip: Complementary rule: P(A) + P(not A) = 1. Always.', sort_order: 255 },
  { id: 'dc-gcse-examq-0256', deck_id: 'deck-gcse-exam-questions', front: 'Events A and B are independent. P(A) = 0.3, P(B) = 0.4. Find P(A and B).', back: 'P(A ∩ B) = P(A) × P(B) = 0.3 × 0.4 = 0.12\n\nGCSE Tip: Independent events: P(A∩B) = P(A) × P(B). The outcome of one doesn\'t affect the other.', sort_order: 256 },
  { id: 'dc-gcse-examq-0257', deck_id: 'deck-gcse-exam-questions', front: 'A bag has 4 red and 6 blue balls. Two are drawn WITHOUT replacement. Find P(both red).', back: 'P(1st red) = 4/10\nP(2nd red | 1st red) = 3/9\nP(both red) = (4/10) × (3/9) = 12/90 = 2/15\n\nGCSE Tip: Without replacement: denominator decreases by 1 each draw. Probabilities change.', sort_order: 257 },
  { id: 'dc-gcse-examq-0258', deck_id: 'deck-gcse-exam-questions', front: 'A bag has 4 red and 6 blue balls. Two are drawn WITH replacement. Find P(both blue).', back: 'P(blue) = 6/10 for each draw\nP(both blue) = (6/10) × (6/10) = 36/100 = 9/25\n\nGCSE Tip: With replacement: probabilities stay the same for each draw. Events are independent.', sort_order: 258 },
  { id: 'dc-gcse-examq-0259', deck_id: 'deck-gcse-exam-questions', front: 'A card is drawn from a standard pack of 52. Find P(heart or king).', back: 'P(heart) = 13/52, P(king) = 4/52, P(king of hearts) = 1/52\nP(heart or king) = 13/52 + 4/52 − 1/52 = 16/52 = 4/13\n\nGCSE Tip: Use the addition formula. Don\'t double-count the king of hearts.', sort_order: 259 },
  { id: 'dc-gcse-examq-0260', deck_id: 'deck-gcse-exam-questions', front: '60 students: 35 study French, 28 study Spanish, 12 study both. Find P(studies neither).', back: 'Studies at least one = 35 + 28 − 12 = 51\nStudies neither = 60 − 51 = 9\nP(neither) = 9/60 = 3/20\n\nGCSE Tip: Use inclusion-exclusion: |F∪S| = |F|+|S|−|F∩S|. Then subtract from total.', sort_order: 260 },
  { id: 'dc-gcse-examq-0261', deck_id: 'deck-gcse-exam-questions', front: 'A game costs £2 to play. P(win £5) = 0.3, P(win £1) = 0.4, otherwise lose. Is it worth playing?', back: 'Expected winnings = 5×0.3 + 1×0.4 + 0×0.3 = 1.5 + 0.4 + 0 = £1.90\nCost to play = £2.00\nNet expected value = £1.90 − £2.00 = −£0.10\nNot worth playing (expected loss of 10p per game).\n\nGCSE Tip: Expected value = Σ(outcome × probability). If EV < cost, don\'t play.', sort_order: 261 },
  { id: 'dc-gcse-examq-0262', deck_id: 'deck-gcse-exam-questions', front: 'P(A) = 0.4 and P(A ∩ B) = 0.12. Find the conditional probability P(B|A).', back: 'P(B|A) = P(A ∩ B) / P(A) = 0.12 / 0.4 = 0.3\n\nGCSE Tip: Conditional probability formula: P(B|A) = P(A∩B)/P(A). Read as "probability of B given A".', sort_order: 262 },
  { id: 'dc-gcse-examq-0263', deck_id: 'deck-gcse-exam-questions', front: 'From a Venn diagram: A = {2,4,6,8,10}, B = {4,8,12,16}. List A∩B and A∪B.', back: 'A ∩ B = {4, 8} (in both sets)\nA ∪ B = {2, 4, 6, 8, 10, 12, 16} (in A or B or both)\n\nGCSE Tip: ∩ = intersection (overlap). ∪ = union (everything in either or both).', sort_order: 263 },
  { id: 'dc-gcse-examq-0264', deck_id: 'deck-gcse-exam-questions', front: 'Three coins are flipped. Find P(at least 2 heads).', back: 'Sample space: HHH, HHT, HTH, THH, HTT, THT, TTH, TTT (8 outcomes)\nAt least 2 heads: HHH, HHT, HTH, THH = 4 outcomes\nP(at least 2 heads) = 4/8 = 1/2\n\nGCSE Tip: "At least" = include the boundary value. List all outcomes or use complementary rule.', sort_order: 264 },
  { id: 'dc-gcse-examq-0265', deck_id: 'deck-gcse-exam-questions', front: 'The probability of winning a game is 0.25. Find the expected number of wins in 80 games.', back: 'Expected wins = 0.25 × 80 = 20\n\nGCSE Tip: Expected frequency = probability × number of trials.', sort_order: 265 },
  { id: 'dc-gcse-examq-0266', deck_id: 'deck-gcse-exam-questions', front: 'In a class of 30, 18 like maths, 15 like science, 7 like both. Find P(likes at least one subject).', back: 'At least one = 18 + 15 − 7 = 26 students\nP(at least one) = 26/30 = 13/15\n\nGCSE Tip: Inclusion-exclusion: |M∪S| = |M|+|S|−|M∩S|.', sort_order: 266 },
  { id: 'dc-gcse-examq-0267', deck_id: 'deck-gcse-exam-questions', front: 'If P(A|B) = P(A), what does this tell us about events A and B?', back: 'A and B are independent.\nKnowing B has occurred does not change the probability of A.\n\nGCSE Tip: Definition of independence: P(A|B) = P(A), which means P(A∩B) = P(A)×P(B).', sort_order: 267 },
  { id: 'dc-gcse-examq-0268', deck_id: 'deck-gcse-exam-questions', front: 'A family has 3 children. Assuming P(boy) = P(girl) = 0.5, find P(all same gender).', back: 'P(all boys) = (1/2)³ = 1/8\nP(all girls) = (1/2)³ = 1/8\nP(all same) = 1/8 + 1/8 = 2/8 = 1/4\n\nGCSE Tip: "All same" = all boys OR all girls. Add the two probabilities.', sort_order: 268 },
  { id: 'dc-gcse-examq-0269', deck_id: 'deck-gcse-exam-questions', front: 'Two events have P(A) = 0.6, P(B) = 0.4. If they are mutually exclusive, find P(A ∩ B) and P(A ∪ B).', back: 'Mutually exclusive: P(A ∩ B) = 0\nP(A ∪ B) = P(A) + P(B) = 0.6 + 0.4 = 1.0\n\nGCSE Tip: Mutually exclusive events cannot occur at the same time. Their union covers the whole sample space here.', sort_order: 269 },
  { id: 'dc-gcse-examq-0270', deck_id: 'deck-gcse-exam-questions', front: 'A bag has n red balls and 4 blue balls. P(red) = 1/3. Find n.', back: 'P(red) = n/(n+4) = 1/3\n3n = n + 4\n2n = 4\nn = 2\n\nGCSE Tip: Set up the probability fraction equal to the given value and solve algebraically.', sort_order: 270 },

  // HIGHER ONLY (271-300)
  { id: 'dc-gcse-examq-0271', deck_id: 'deck-gcse-exam-questions', front: 'Find the iteration formula for x³ + x − 5 = 0. Use x₀ = 1 to find x₁ and x₂.', back: 'Rearrange: x³ = 5 − x → x = ³√(5−x)\nIteration: xₙ₊₁ = ³√(5 − xₙ)\nx₁ = ³√(5−1) = ³√4 ≈ 1.587\nx₂ = ³√(5−1.587) = ³√3.413 ≈ 1.503\n\nGCSE Tip: Rearrange to x = f(x) form. Apply the formula repeatedly to converge on the root.', sort_order: 271 },
  { id: 'dc-gcse-examq-0272', deck_id: 'deck-gcse-exam-questions', front: 'Show by trial and improvement (iteration) that x³ + x = 5 has a solution between x = 1 and x = 2.', back: 'At x=1: 1+1=2 < 5\nAt x=2: 8+2=10 > 5\nSince f(1)<5<f(2) and f is continuous, there is a root between 1 and 2 by the change of sign.\n\nGCSE Tip: Evaluate both ends. If signs change (one < target, one > target), there is a root between them.', sort_order: 272 },
  { id: 'dc-gcse-examq-0273', deck_id: 'deck-gcse-exam-questions', front: 'For f(x) = x² + 3, find ff(x).', back: 'f(x) = x² + 3\nff(x) = f(f(x)) = f(x²+3) = (x²+3)² + 3\n= x⁴ + 6x² + 9 + 3 = x⁴ + 6x² + 12\n\nGCSE Tip: ff(x) means apply f twice. Substitute f(x) into f(x) again.', sort_order: 273 },
  { id: 'dc-gcse-examq-0274', deck_id: 'deck-gcse-exam-questions', front: 'If f(x) = 2x − 1, find f⁻¹(x) and verify ff⁻¹(x) = x.', back: 'y = 2x − 1 → x = (y+1)/2 → f⁻¹(x) = (x+1)/2\nVerify: f(f⁻¹(x)) = f((x+1)/2) = 2×(x+1)/2 − 1 = x+1−1 = x ✓\n\nGCSE Tip: Inverse function undoes the original. Always verify by showing ff⁻¹(x) = x.', sort_order: 274 },
  { id: 'dc-gcse-examq-0275', deck_id: 'deck-gcse-exam-questions', front: 'Sketch y = x²(x − 2). Identify where the graph crosses and touches the x-axis.', back: 'Roots: x² = 0 → x = 0 (double root, TOUCHES x-axis)\nx − 2 = 0 → x = 2 (single root, CROSSES x-axis)\ny-intercept: (0, 0)\nFor large x: y → +∞ (positive cubic)\n\nGCSE Tip: Double root → curve touches and bounces off. Single root → curve crosses.', sort_order: 275 },
  { id: 'dc-gcse-examq-0276', deck_id: 'deck-gcse-exam-questions', front: 'Solve algebraically: the circle x² + y² = 25 and the line y = x + 1.', back: 'Substitute y = x+1 into circle:\nx² + (x+1)² = 25\nx² + x² + 2x + 1 = 25\n2x² + 2x − 24 = 0\nx² + x − 12 = 0\n(x+4)(x−3) = 0\nx = −4 or x = 3\ny = −3 or y = 4\nIntersections: (−4,−3) and (3,4)\n\nGCSE Tip: Substitute the linear equation into the circle equation to form a quadratic.', sort_order: 276 },
  { id: 'dc-gcse-examq-0277', deck_id: 'deck-gcse-exam-questions', front: 'In vector terms, OABC is a parallelogram. OA = a and OC = c. Express OB in terms of a and c.', back: 'In a parallelogram, OB = OA + AB\nAB = OC = c (opposite sides are equal and parallel)\nOB = a + c\n\nGCSE Tip: In a parallelogram, the diagonal vector = sum of adjacent side vectors.', sort_order: 277 },
  { id: 'dc-gcse-examq-0278', deck_id: 'deck-gcse-exam-questions', front: 'OA = a and OB = b. M is the midpoint of AB. Find OM in terms of a and b.', back: 'AM = (1/2)AB = (1/2)(b − a)\nOM = OA + AM = a + (1/2)(b−a) = a + b/2 − a/2 = (a+b)/2\n\nGCSE Tip: OM = (a+b)/2. This is the vector form of the midpoint formula.', sort_order: 278 },
  { id: 'dc-gcse-examq-0279', deck_id: 'deck-gcse-exam-questions', front: 'Find the stationary points of y = x³ − 3x and determine their nature.', back: 'dy/dx = 3x² − 3 = 0 → x² = 1 → x = ±1\nd²y/dx² = 6x\nAt x = 1: d²y/dx² = 6 > 0 → minimum, y = 1−3 = −2 → (1,−2)\nAt x = −1: d²y/dx² = −6 < 0 → maximum, y = −1+3 = 2 → (−1,2)\n\nGCSE Tip: Set dy/dx=0 to find stationary points. Use d²y/dx² to classify: +ve→min, −ve→max.', sort_order: 279 },
  { id: 'dc-gcse-examq-0280', deck_id: 'deck-gcse-exam-questions', front: 'Find the equation of the normal to the curve y = x² at the point (2, 4).', back: 'dy/dx = 2x. At x=2: gradient of tangent = 4.\nGradient of normal = −1/4\ny − 4 = −(1/4)(x − 2)\n4y − 16 = −x + 2\nx + 4y = 18\n\nGCSE Tip: Normal is perpendicular to the tangent. Use gradient × (−1/gradient of tangent) for normal.', sort_order: 280 },
  { id: 'dc-gcse-examq-0281', deck_id: 'deck-gcse-exam-questions', front: 'Integrate ∫(2x + 3) dx.', back: '∫(2x + 3) dx = x² + 3x + c\n\nGCSE Tip: Increase power by 1, divide by new power. Don\'t forget the constant of integration +c.', sort_order: 281 },
  { id: 'dc-gcse-examq-0282', deck_id: 'deck-gcse-exam-questions', front: 'Find the area under y = x² between x = 0 and x = 3.', back: '∫₀³ x² dx = [x³/3]₀³ = 27/3 − 0 = 9 square units\n\nGCSE Tip: Area = ∫ₐᵇ f(x) dx. Substitute upper limit then subtract lower limit substitution.', sort_order: 282 },
  { id: 'dc-gcse-examq-0283', deck_id: 'deck-gcse-exam-questions', front: 'Prove that for any integer n, n(n + 1) is always even.', back: 'Case 1: n is even. Then n = 2k, so n(n+1) = 2k(n+1) — divisible by 2. ✓\nCase 2: n is odd. Then n+1 is even, so n+1 = 2k, making n(n+1) = n×2k — divisible by 2. ✓\nIn either case, n(n+1) is even.\n\nGCSE Tip: Proof by exhaustion: consider all possible cases (even n and odd n) separately.', sort_order: 283 },
  { id: 'dc-gcse-examq-0284', deck_id: 'deck-gcse-exam-questions', front: 'Show that √2 is irrational (proof by contradiction).', back: 'Assume √2 = p/q in lowest terms (p, q integers, no common factors).\n2 = p²/q² → p² = 2q² → p² is even → p is even (p = 2k)\n(2k)² = 2q² → 4k² = 2q² → q² = 2k² → q² is even → q is even\nBut then p and q are both even → contradiction (we said no common factors).\nTherefore √2 is irrational. ✓\n\nGCSE Tip: Proof by contradiction — assume rational, derive a contradiction.', sort_order: 284 },
  { id: 'dc-gcse-examq-0285', deck_id: 'deck-gcse-exam-questions', front: 'The equation kx² + 3x + 1 = 0 has equal roots. Find the value of k.', back: 'Equal roots when discriminant = 0: b² − 4ac = 0\n9 − 4(k)(1) = 0\n4k = 9\nk = 9/4\n\nGCSE Tip: Discriminant b²−4ac: = 0 → equal roots; > 0 → two distinct roots; < 0 → no real roots.', sort_order: 285 },
  { id: 'dc-gcse-examq-0286', deck_id: 'deck-gcse-exam-questions', front: 'Given p = 3 + 2√5 and q = 3 − 2√5. Find p + q and pq without a calculator.', back: 'p + q = (3+2√5) + (3−2√5) = 6\npq = (3+2√5)(3−2√5) = 9 − (2√5)² = 9 − 20 = −11\n\nGCSE Tip: Conjugate surds: (a+b√c)(a−b√c) = a²−b²c. No surds in the result.', sort_order: 286 },
  { id: 'dc-gcse-examq-0287', deck_id: 'deck-gcse-exam-questions', front: 'For y = 2x³ − 9x² + 12x, find where the function is increasing.', back: 'dy/dx = 6x² − 18x + 12 = 6(x²−3x+2) = 6(x−1)(x−2)\ndy/dx > 0 when (x−1)(x−2) > 0\nSolution: x < 1 or x > 2\nFunction is increasing for x < 1 and x > 2.\n\nGCSE Tip: Increasing where dy/dx > 0. Find stationary points, then test intervals.', sort_order: 287 },
  { id: 'dc-gcse-examq-0288', deck_id: 'deck-gcse-exam-questions', front: 'Simplify (x² − 1)/(x + 1) and state any restrictions on x.', back: '(x²−1) = (x+1)(x−1)\n(x+1)(x−1)/(x+1) = x − 1  [provided x ≠ −1]\n\nGCSE Tip: Factorise as difference of two squares. State x ≠ −1 (division by zero).', sort_order: 288 },
  { id: 'dc-gcse-examq-0289', deck_id: 'deck-gcse-exam-questions', front: 'Solve algebraically to find all values of x satisfying both x² > 4 and x < 3.', back: 'x² > 4 → x > 2 or x < −2\nCombined with x < 3:\nx > 2 AND x < 3 → 2 < x < 3\nx < −2 AND x < 3 → x < −2\nSolution: x < −2 or 2 < x < 3\n\nGCSE Tip: Solve each inequality separately, then find the intersection/union as appropriate.', sort_order: 289 },
  { id: 'dc-gcse-examq-0290', deck_id: 'deck-gcse-exam-questions', front: 'Rearrange to find x: (x + 1)/(x − 1) = (x + 2)/(x + 3).', back: 'Cross-multiply: (x+1)(x+3) = (x+2)(x−1)\nx²+4x+3 = x²+x−2\n4x+3 = x−2\n3x = −5\nx = −5/3\n\nGCSE Tip: Cross-multiply to clear fractions, expand, simplify. Check denominators are non-zero.', sort_order: 290 },
  { id: 'dc-gcse-examq-0291', deck_id: 'deck-gcse-exam-questions', front: 'Show that 2n + 1 is always odd if n is an integer.', back: '2n is always even (multiple of 2).\n2n + 1 = even number + 1 = odd number.\nAlternatively: 2n+1 is of the form 2k+1 (with k=n), which is the definition of an odd number. ✓\n\nGCSE Tip: An odd number can always be written as 2n+1. Showing the form directly proves it.', sort_order: 291 },
  { id: 'dc-gcse-examq-0292', deck_id: 'deck-gcse-exam-questions', front: 'Prove that the sum of any three consecutive integers is divisible by 3.', back: 'Let the integers be n, n+1, n+2.\nSum = n + (n+1) + (n+2) = 3n + 3 = 3(n+1)\n3(n+1) is divisible by 3 for all integer values of n. ✓\n\nGCSE Tip: Represent consecutive integers as n, n+1, n+2. Factorise to show divisibility.', sort_order: 292 },
  { id: 'dc-gcse-examq-0293', deck_id: 'deck-gcse-exam-questions', front: 'Find the x-intercepts of y = x³ − 4x. Hence sketch the curve.', back: 'x³ − 4x = 0 → x(x²−4) = 0 → x(x+2)(x−2) = 0\nRoots: x = 0, x = −2, x = 2\nAll three are single roots (cross at each).\nPositive cubic (rises right, falls left).\n\nGCSE Tip: Factorise fully to find all roots. Positive leading coefficient → curve goes top-right.', sort_order: 293 },
  { id: 'dc-gcse-examq-0294', deck_id: 'deck-gcse-exam-questions', front: 'Given vector a = (3, 1) and vector b = (−1, 4), find |a + b| and |a − b|.', back: 'a + b = (3+(−1), 1+4) = (2, 5)\n|a+b| = √(4+25) = √29\na − b = (3−(−1), 1−4) = (4, −3)\n|a−b| = √(16+9) = √25 = 5\n\nGCSE Tip: Add/subtract components separately. Magnitude = √(x²+y²).', sort_order: 294 },
  { id: 'dc-gcse-examq-0295', deck_id: 'deck-gcse-exam-questions', front: 'In a triangle OAB, OA = a and OB = b. P divides AB in ratio 2:1. Find OP in terms of a and b.', back: 'AP = (2/3)AB = (2/3)(b−a)\nOP = OA + AP = a + (2/3)(b−a) = a + (2/3)b − (2/3)a = (1/3)a + (2/3)b\n\nGCSE Tip: Use the ratio to find what fraction of AB from A. OP = OA + (fraction)×AB.', sort_order: 295 },
  { id: 'dc-gcse-examq-0296', deck_id: 'deck-gcse-exam-questions', front: 'Show that the points A(1,2), B(3,8) and C(5,14) are collinear (lie on a straight line).', back: 'Gradient AB = (8−2)/(3−1) = 6/2 = 3\nGradient BC = (14−8)/(5−3) = 6/2 = 3\nSame gradient and share point B → A, B, C are collinear.\n\nGCSE Tip: Show equal gradients between adjacent pairs and that they share a point.', sort_order: 296 },
  { id: 'dc-gcse-examq-0297', deck_id: 'deck-gcse-exam-questions', front: 'Find the gradient function (derivative) of y = 4x³ − 3x² + 2x − 7.', back: 'dy/dx = 12x² − 6x + 2\n\nGCSE Tip: Differentiate term by term: d/dx[axⁿ] = naxⁿ⁻¹. Constants differentiate to 0.', sort_order: 297 },
  { id: 'dc-gcse-examq-0298', deck_id: 'deck-gcse-exam-questions', front: 'Solve sin²θ + sin θ = 0 for 0° ≤ θ ≤ 360°.', back: 'sin θ(sin θ + 1) = 0\nsin θ = 0: θ = 0°, 180°, 360°\nsin θ = −1: θ = 270°\nSolutions: 0°, 180°, 270°, 360°\n\nGCSE Tip: Factorise the trig equation. Solve each factor separately across the full range.', sort_order: 298 },
  { id: 'dc-gcse-examq-0299', deck_id: 'deck-gcse-exam-questions', front: 'A sequence is defined by uₙ₊₁ = 2uₙ − 1, u₁ = 5. Find u₂, u₃, u₄ and suggest a formula for uₙ.', back: 'u₂ = 2(5)−1 = 9\nu₃ = 2(9)−1 = 17\nu₄ = 2(17)−1 = 33\nSequence: 5, 9, 17, 33... differences: 4, 8, 16 (doubling)\nuₙ = 2ⁿ + 3 (check: u₁=2+3=5✓, u₂=4+3=7... wait: u₁=5=2¹+3=5✓ u₂=2²+3=7≠9)\nActual: uₙ = 3×2ⁿ⁻¹ + 2 → check: n=1: 3+2=5✓ n=2: 6+2=8≠9. \nCorrect: uₙ = 2ⁿ⁻¹×4 + 1 → n=1:4+1=5✓ n=2:8+1=9✓ n=3:16+1=17✓ n=4:32+1=33✓\nuₙ = 4×2ⁿ⁻¹ + 1 = 2ⁿ⁺¹ + 1\n\nGCSE Tip: Apply the recurrence relation step by step. Look for the pattern in the sequence.', sort_order: 299 },
  { id: 'dc-gcse-examq-0300', deck_id: 'deck-gcse-exam-questions', front: 'Prove that the exterior angle of a triangle equals the sum of the two non-adjacent interior angles.', back: 'Let triangle ABC have angles a, b, c. Extend side BC to point D.\nAngles on a straight line: c + angle ACD = 180°\nAngles in triangle: a + b + c = 180°\nSo angle ACD = 180° − c = a + b ✓\nThe exterior angle = sum of the two opposite interior angles.\n\nGCSE Tip: Use "angles on a straight line = 180°" and "angles in a triangle = 180°" together.', sort_order: 300 },
];
